{
  "name": "Transforme Neural Logistics",
  "description": "Plataforma avanzada de gestión logística con IA multimodal e integración financiera.",
  "requestFramePermissions": [
    "geolocation",
    "microphone",
    "camera"
  ]
}

export const notificationService = {
  requestPermission: async () => {
    if ('Notification' in window) {
      return await Notification.requestPermission();
    }
    return 'denied';
  },

  playAlert: (type: 'success' | 'alert' | 'info' = 'info') => {
    const sounds = {
      success: 'https://assets.mixkit.co/active_storage/sfx/2354/2354-preview.mp3',
      alert: 'https://assets.mixkit.co/active_storage/sfx/2358/2358-preview.mp3',
      info: 'https://assets.mixkit.co/active_storage/sfx/2354/2354-preview.mp3'
    };
    const audio = new Audio(sounds[type]);
    audio.play().catch(e => console.log('Audio feedback disabled by browser policy'));
  },

  notify: (title: string, body: string) => {
    notificationService.playAlert('info');
    if (Notification.permission === 'granted') {
      new Notification(title, {
        body,
        icon: 'https://cdn-icons-png.flaticon.com/512/3063/3063822.png'
      });
    }
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import Estructura from './components/Layout';
import OrderManagementView from './components/OrderManagementView';
import VoiceCommandCenter from './components/VoiceCommandCenter';
import HybridSupportView from './components/HybridSupportView';
import StoreOnboardingView from './components/StoreOnboardingView';
import DriverOnboardingView from './components/DriverOnboardingView';
import WalletView from './components/WalletView';
import InfrastructureOpsView from './components/VercelOpsView';
import MobileSimulator from './components/MobileSimulator';
import LoginView from './components/LoginView';
import { apiService } from './services/apiService';
import { notificationService } from './services/notificationService';
import { Pedido, EstadoPedido, SocioRepartidor, Comercio } from './types';

const App: React.FC = () => {
  const [user, setUser] = useState<any>(null);
  const [pestañaActiva, setPestañaActiva] = useState('tablero');
  const [pedidos, setPedidos] = useState<Pedido[]>([]);
  const [repartidores, setRepartidores] = useState<SocioRepartidor[]>([]);
  const [comercios, setComercios] = useState<Comercio[]>([]);
  const [cargando, setCargando] = useState(true);
  const [toast, setToast] = useState<{ message: string, type: 'error' | 'success' | 'info' } | null>(null);
  const [showSimulator, setShowSimulator] = useState(false);

  const fetchData = useCallback(async (isSilent = false) => {
    if (!isSilent) setCargando(true);
    try {
      const [o, d, c] = await Promise.all([
        apiService.fetchOrders().catch(() => []),
        apiService.getDrivers().catch(() => []),
        apiService.getStores().catch(() => [])
      ]);

      // Lógica de notificación si cambia el estado del primer pedido (demo)
      if (pedidos.length > 0 && o.length > 0 && o[0].estado !== pedidos[0].estado) {
        notificationService.notify("Actualización de Red", `Pedido #${o[0].id} ahora está ${o[0].estado}`);
      }

      setPedidos(o as Pedido[]);
      setRepartidores(d as SocioRepartidor[]);
      setComercios(c as Comercio[]);
    } catch (err) { 
      console.warn("[TRANSFORME] Sincronización local activa."); 
    } finally { 
      setCargando(false); 
    }
  }, [pedidos]);

  useEffect(() => { 
    if (user) {
      fetchData();
      notificationService.requestPermission();
      const interval = setInterval(() => fetchData(true), 20000); 
      return () => clearInterval(interval);
    }
  }, [fetchData, user]);

  if (!user) return <LoginView onLogin={setUser} />;

  if (cargando && pedidos.length === 0) return (
    <div className="h-screen bg-black flex flex-col items-center justify-center overflow-hidden">
      <div className="relative">
         <h1 className="text-6xl md:text-8xl font-black italic text-white uppercase animate-pulse tracking-tighter relative z-10">TRANSFORME<span className="text-plus-blue">.</span></h1>
         <div className="absolute -inset-10 bg-plus-blue/10 blur-[100px] rounded-full"></div>
      </div>
      <div className="mt-12 flex flex-col items-center">
        <div className="w-48 h-1 bg-white/10 rounded-full overflow-hidden mb-4">
           <div className="h-full bg-plus-blue animate-[shimmer_2s_infinite_linear] w-1/3"></div>
        </div>
        <p className="text-[10px] text-white/30 font-black uppercase tracking-[0.5em] animate-pulse">Autenticando Nodo Central...</p>
      </div>
    </div>
  );

  return (
    <Estructura 
      pestañaActiva={pestañaActiva} 
      setPestañaActiva={setPestañaActiva}
      toast={toast}
      onClearToast={() => setToast(null)}
    >
      {pestañaActiva === 'tablero' && (
        <OrderManagementView 
          pedidos={pedidos} 
          repartidores={repartidores} 
          onAssign={(oid, did) => {
            notificationService.playAlert('success');
            apiService.assignOrder(oid, did).then(() => fetchData(true));
          }} 
          onUpdateStatus={(oid, status) => {
            notificationService.playAlert('info');
            apiService.updateOrder(oid, status).then(() => fetchData(true));
          }} 
        />
      )}
      {pestañaActiva === 'voice-command' && <VoiceCommandCenter />}
      {pestañaActiva === 'hybrid-support' && <HybridSupportView />}
      {pestañaActiva === 'alta-socio' && <DriverOnboardingView />}
      {pestañaActiva === 'billetera' && <WalletView />}
      {pestañaActiva === 'vercel' && <InfrastructureOpsView />}

      <button 
        onClick={() => setShowSimulator(true)}
        className="fixed bottom-10 right-10 z-[100] bg-black text-white px-8 py-6 rounded-[2.5rem] shadow-2xl font-black uppercase tracking-widest text-xs flex items-center gap-4 hover:scale-105 transition-all border border-white/10"
      >
        <span className="text-xl">🛵</span>
        Simulador
      </button>

      {repartidores.length > 0 && (
        <MobileSimulator 
          isOpen={showSimulator}
          onClose={() => setShowSimulator(false)}
          driver={repartidores[0]}
          activeOrders={pedidos.filter(p => p.estado === EstadoPedido.ACEPTADO || p.estado === EstadoPedido.PENDIENTE)}
          onOrderAccepted={(id) => apiService.updateOrder(id, EstadoPedido.ACEPTADO).then(() => fetchData(true))}
          onOrderDelivered={(id) => {
            notificationService.notify("Pedido Entregado", `El pedido #${id} ha sido completado.`);
            apiService.updateOrder(id, EstadoPedido.ENTREGADO).then(() => fetchData(true));
          }}
        />
      )}
    </Estructura>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { mercadoPagoService, MPBalance } from '../services/mercadoPagoService';
import { notificationService } from '../services/notificationService';
import { Transaccion } from '../types';
import { GoogleGenAI } from "@google/genai";

const WalletView: React.FC = () => {
  const [balance, setBalance] = useState<MPBalance | null>(null);
  const [history, setHistory] = useState<Transaccion[]>([]);
  const [loading, setLoading] = useState(true);
  const [iaAdvice, setIaAdvice] = useState('Analizando tendencias financieras...');
  const [isProcessing, setIsProcessing] = useState(false);

  const fetchFinanceData = async () => {
    setLoading(true);
    try {
      const [b, h] = await Promise.all([
        mercadoPagoService.getBalance(),
        mercadoPagoService.getHistorialTransacciones()
      ]);
      setBalance(b);
      setHistory(h);

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Analiza este balance: $${b.total_amount}. Da un consejo estratégico corto.`
      });
      setIaAdvice(response.text || "Liquidez óptima. Considerar expansión de flota.");
    } catch (err) {
      setIaAdvice("Operativa financiera estable. Mantener reservas.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchFinanceData();
  }, []);

  const handleWithdraw = async () => {
    setIsProcessing(true);
    notificationService.playAlert('info');
    await new Promise(resolve => setTimeout(resolve, 2000));
    notificationService.notify("Retiro Exitoso", "Tus fondos están siendo procesados.");
    setIsProcessing(false);
  };

  if (loading) return (
    <div className="h-[600px] flex flex-col items-center justify-center gap-8 bg-white rounded-[5rem] border border-black/5">
      <div className="w-16 h-16 border-4 border-plus-blue border-t-transparent rounded-full animate-spin"></div>
      <p className="text-[10px] font-black uppercase tracking-[0.5em] text-slate-300">Sincronizando Liquid Matrix...</p>
    </div>
  );

  return (
    <div className="space-y-16 animate-in fade-in duration-700">
      <header className="flex flex-col lg:flex-row justify-between items-start lg:items-end gap-12">
        <div>
          <p className="text-slate-400 font-black uppercase tracking-[0.4em] text-[10px] mb-4">Financial Dashboard</p>
          <h2 className="text-[80px] font-black tracking-tighter leading-[0.8] uppercase italic text-black">
            Neural<br/><span className="text-plus-blue">Liquidity</span>
          </h2>
        </div>
        <div className="flex flex-col gap-4">
          <div className="bg-white p-6 px-10 rounded-[2.5rem] border border-black/5 shadow-xl flex items-center gap-6">
            <img src="https://logodownload.org/wp-content/uploads/2019/06/mercado-pago-logo-0.png" className="h-6" alt="MP" />
            <div className="h-8 w-px bg-slate-100"></div>
            <div>
              <p className="text-[9px] font-black uppercase text-slate-400">Estado de Vínculo</p>
              <p className="text-xs font-bold uppercase tracking-widest text-emerald-500">Activo ✓</p>
            </div>
          </div>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
        <div className="lg:col-span-8 bg-[#050505] text-white p-16 rounded-[4.5rem] shadow-3xl relative overflow-hidden group">
           <div className="relative z-10 flex flex-col h-full justify-between">
              <div>
                <p className="text-[11px] font-black text-plus-blue uppercase tracking-[0.6em] italic mb-12">Capital en Red</p>
                <h3 className="text-[110px] font-black tracking-tighter leading-none italic">
                   <span className="text-4xl text-white/20">$</span>
                   {balance?.total_amount.toLocaleString()}
                </h3>
              </div>
              <div className="grid grid-cols-2 gap-10 mt-16">
                 <div className="bg-white/5 p-10 rounded-[2.5rem] border border-white/5 backdrop-blur-md">
                    <p className="text-[8px] font-black opacity-30 uppercase tracking-widest mb-3">Disponible</p>
                    <p className="text-3xl font-black italic text-emerald-400">${balance?.available_balance.toLocaleString()}</p>
                 </div>
                 <div className="bg-white/5 p-10 rounded-[2.5rem] border border-white/5 opacity-60">
                    <p className="text-[8px] font-black opacity-30 uppercase tracking-widest mb-3">Retención</p>
                    <p className="text-3xl font-black italic">${balance?.unavailable_balance.toLocaleString()}</p>
                 </div>
              </div>
           </div>
           <div className="absolute -bottom-20 -right-20 text-[25rem] opacity-[0.03] font-black pointer-events-none italic">TRANSFORME</div>
        </div>

        <div className="lg:col-span-4 bg-white p-12 rounded-[4.5rem] border border-black/5 shadow-2xl flex flex-col justify-between">
           <div className="space-y-10">
              <div className="flex items-center gap-4">
                 <div className="w-10 h-10 bg-black rounded-full flex items-center justify-center text-white font-bold animate-pulse">🤖</div>
                 <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-400">Insight Neural</h4>
              </div>
              <div className="p-8 bg-slate-50 rounded-[3rem] border-l-8 border-plus-blue">
                <p className="text-2xl font-black italic leading-tight text-black">"{iaAdvice}"</p>
              </div>
           </div>

           <div className="flex flex-col gap-4 mt-12">
              <button 
                onClick={handleWithdraw}
                disabled={isProcessing}
                className="w-full bg-black text-white py-7 rounded-[2.5rem] text-[10px] font-black uppercase tracking-widest shadow-xl"
              >
                {isProcessing ? 'Procesando...' : 'Retirar a Cuenta Bancaria'}
              </button>
           </div>
        </div>
      </div>

      <div className="bg-white p-14 rounded-[5rem] border border-black/5 shadow-2xl overflow-hidden">
         <h4 className="text-3xl font-black uppercase tracking-tighter italic mb-12">Registro de <span className="text-plus-blue">Flujos</span></h4>
         <div className="space-y-4">
            {history.map(tx => (
              <div key={tx.id} className="flex items-center justify-between p-8 bg-slate-50 rounded-[3rem] border border-black/5">
                 <div className="flex items-center gap-8">
                    <div className={`w-14 h-14 rounded-[1.2rem] flex items-center justify-center text-xl ${tx.monto > 0 ? 'bg-emerald-100 text-emerald-600' : 'bg-red-50 text-red-500'}`}>
                       {tx.monto > 0 ? '↗' : '↘'}
                    </div>
                    <div>
                       <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">{tx.tipo}</p>
                       <p className="text-lg font-black uppercase italic text-slate-800">{tx.detalle}</p>
                    </div>
                 </div>
                 <p className={`text-3xl font-black italic ${tx.monto > 0 ? 'text-emerald-600' : 'text-slate-900'}`}>
                    {tx.monto > 0 ? '+' : ''}{tx.monto.toLocaleString()}
                 </p>
              </div>
            ))}
         </div>
      </div>
    </div>
  );
};

export default WalletView;

import React, { useState, useMemo } from 'react';
import { Pedido, SocioRepartidor, EstadoPedido } from '../types';
import StatusBadge from './StatusBadge';
import InteractiveMap from './InteractiveMap';

interface OrderManagementViewProps {
  pedidos: Pedido[];
  repartidores: SocioRepartidor[];
  onAssign: (orderId: any, driverId: any) => void;
  onUpdateStatus: (orderId: any, status: EstadoPedido) => void;
}

const OrderManagementView: React.FC<OrderManagementViewProps> = ({ pedidos, repartidores, onAssign, onUpdateStatus }) => {
  const [filter, setFilter] = useState<'ALL' | EstadoPedido>('ALL');
  const [selectedId, setSelectedId] = useState<string | number | null>(null);

  const filteredOrders = useMemo(() => {
    if (filter === 'ALL') return pedidos;
    return pedidos.filter(p => p.estado === filter);
  }, [pedidos, filter]);

  const stats = useMemo(() => ({
    total: pedidos.length,
    pending: pedidos.filter(p => p.estado === 'PENDIENTE').length,
    active: pedidos.filter(p => p.estado === 'EN_CAMINO' || p.estado === 'ACEPTADO').length
  }), [pedidos]);

  const selectedOrder = useMemo(() => 
    pedidos.find(p => p.id === selectedId), [pedidos, selectedId]
  );

  return (
    <div className="flex flex-col gap-12 animate-in fade-in duration-700">
      <header className="flex flex-col md:flex-row justify-between items-end gap-10">
        <div>
          <h2 className="text-7xl font-black tracking-tighter italic uppercase text-black leading-none">
            Command <span className="text-plus-blue">Center</span>
          </h2>
          <div className="flex gap-8 mt-6">
             <div>
                <p className="text-[8px] font-black uppercase text-slate-400 tracking-widest">En Red</p>
                <p className="text-2xl font-black italic">{stats.total}</p>
             </div>
             <div>
                <p className="text-[8px] font-black uppercase text-amber-500 tracking-widest">Pendientes</p>
                <p className="text-2xl font-black italic">{stats.pending}</p>
             </div>
             <div>
                <p className="text-[8px] font-black uppercase text-emerald-500 tracking-widest">Activos</p>
                <p className="text-2xl font-black italic">{stats.active}</p>
             </div>
          </div>
        </div>

        <div className="flex bg-slate-100 p-2 rounded-[2.5rem] border border-black/5">
           {['ALL', 'PENDIENTE', 'ACEPTADO', 'EN_CAMINO', 'ENTREGADO'].map(status => (
             <button 
               key={status}
               onClick={() => setFilter(status as any)}
               className={`px-6 py-3 rounded-[2rem] text-[9px] font-black uppercase tracking-widest transition-all ${filter === status ? 'bg-black text-white shadow-xl' : 'text-black/30 hover:text-black'}`}
             >
               {status}
             </button>
           ))}
        </div>
      </header>

      <div className="grid grid-cols-1 xl:grid-cols-12 gap-10 min-h-[700px]">
        <div className="xl:col-span-4 bg-white p-8 rounded-[5rem] border border-black/5 shadow-2xl flex flex-col overflow-hidden">
          <div className="flex-1 overflow-y-auto pr-4 space-y-4 no-scrollbar">
            {filteredOrders.map(order => (
              <div 
                key={order.id}
                onClick={() => setSelectedId(order.id)}
                className={`p-10 rounded-[3.5rem] border transition-all cursor-pointer relative overflow-hidden group ${selectedId === order.id ? 'bg-black text-white border-black' : 'bg-slate-50 border-black/5'}`}
              >
                <div className="flex justify-between items-start mb-6">
                  <h4 className="text-2xl font-black italic uppercase tracking-tighter leading-none">{order.nombreCliente}</h4>
                  <StatusBadge status={order.estado} />
                </div>
                <p className={`text-sm font-bold italic truncate ${selectedId === order.id ? 'text-white/60' : 'text-black/40'}`}>{order.detalles}</p>
                <p className="text-2xl font-black italic tracking-tighter mt-8">${order.monto.toLocaleString()}</p>
              </div>
            ))}
          </div>
        </div>

        <div className="xl:col-span-5 bg-white rounded-[5rem] overflow-hidden border border-black/5 shadow-2xl relative">
            <InteractiveMap 
              center="-27.368,-55.895"
              stores={[]}
              drivers={repartidores}
              className="w-full h-full"
              pickup={selectedOrder ? { lat: selectedOrder.latitud, lng: selectedOrder.longitud } : undefined}
              delivery={selectedOrder ? { lat: selectedOrder.latUsuario, lng: selectedOrder.lngUsuario } : undefined}
            />
        </div>

        <div className="xl:col-span-3 bg-[#0A0A0B] text-white p-12 rounded-[5rem] shadow-3xl flex flex-col border border-white/5">
          {selectedOrder ? (
            <div className="flex flex-col h-full animate-in slide-in-from-right duration-500">
               <h3 className="text-3xl font-black italic uppercase leading-tight mb-10">{selectedOrder.nombreCliente}</h3>

               <div className="flex-1 space-y-6">
                  {!selectedOrder.idRepartidor && (
                    <div className="space-y-4">
                       <p className="text-[9px] font-black text-white/20 uppercase tracking-widest italic">Asignación Manual</p>
                       {repartidores.filter(d => d.etapaIngreso === 'ACTIVO').slice(0, 3).map(driver => (
                         <button 
                            key={driver.id}
                            onClick={() => onAssign(selectedOrder.id, driver.id)}
                            className="w-full bg-white/5 p-6 rounded-2xl border border-white/5 flex items-center justify-between hover:bg-plus-blue transition-all"
                         >
                            <span className="font-black italic uppercase text-xs">{driver.nombre}</span>
                            <span>→</span>
                         </button>
                       ))}
                    </div>
                  )}
                  {selectedOrder.estado !== 'ENTREGADO' && (
                     <button 
                       onClick={() => onUpdateStatus(selectedOrder.id, EstadoPedido.CANCELLED)}
                       className="w-full py-4 border border-red-500/30 text-red-500 rounded-xl text-[9px] font-black uppercase tracking-widest mt-12 hover:bg-red-500 hover:text-white transition-all"
                     >
                       Anular Pedido
                     </button>
                  )}
               </div>

               <button onClick={() => setSelectedId(null)} className="mt-10 w-full py-5 bg-white/5 rounded-2xl text-[9px] font-black uppercase tracking-widest">Cerrar</button>
            </div>
          ) : (
            <div className="flex-1 flex flex-col items-center justify-center text-center opacity-10">
               <p className="text-[12rem] italic font-black">T.</p>
               <p className="text-xs font-black uppercase tracking-[0.5em] italic">Red Neural Operativa</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default OrderManagementView;
